export type SearchCategory = "page" | "setting" | "feature"

export interface SearchItem {
  id: string
  title: string
  description: string
  category: SearchCategory
  /** The parent page name shown as breadcrumb (e.g. "Settings") */
  page: string
  /** Relative route from /dashboard/servers/[id] */
  route: string
  /** Section anchor to scroll to (settings page deep-link) */
  section?: string
  keywords: string[]
  /** Lucide icon name for display */
  iconName: string
  premium?: boolean
  /** "admin" = admin only, "mod" = mod+admin, undefined = everyone */
  requiredLevel?: "admin" | "mod"
}

