const ALL_ITEMS: SearchItem[] = [
  ...PAGE_ITEMS,
  ...SETTINGS_SECTION_ITEMS,
  ...FEATURE_ITEMS,
]

export function getSearchItems(isAdmin: boolean, isMod: boolean): SearchItem[] {
  return ALL_ITEMS.filter((item) => {
    if (item.requiredLevel === "admin" && !isAdmin) return false
    if (item.requiredLevel === "mod" && !isMod && !isAdmin) return false
    return true
  })
}
